"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[6886],{95103(r,n,e){e.r(n),e.d(n,{assets:()=>p,contentTitle:()=>l,default:()=>c,frontMatter:()=>o,metadata:()=>s,toc:()=>i});const s=JSON.parse('{"id":"cpp17/fold-expressions","title":"\u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions)","description":"C++17 \u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp17/04-fold-expressions.md","sourceDirName":"cpp17","slug":"/cpp17/04-fold-expressions","permalink":"/LearnModernCpp/docs/cpp17/04-fold-expressions","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp17","permalink":"/LearnModernCpp/docs/tags/cpp-17"},{"inline":true,"label":"fold_expressions","permalink":"/LearnModernCpp/docs/tags/fold-expressions"}],"version":"current","sidebarPosition":5,"frontMatter":{"sidebar_position":5,"slug":"04-fold-expressions","title":"\u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions)","description":"C++17 \u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions) \u6559\u5b66\u793a\u4f8b","tags":["cpp17","fold_expressions"]},"sidebar":"docs","previous":{"title":"\u7c7b\u6a21\u677f\u53c2\u6570\u63a8\u5bfc CTAD (Class Template Argument Deduction)","permalink":"/LearnModernCpp/docs/cpp17/03-ctad"},"next":{"title":"if constexpr (\u7f16\u8bd1\u671f if)","permalink":"/LearnModernCpp/docs/cpp17/05-constexpr-if"}}');var t=e(74848),a=e(28453);const o={sidebar_position:5,slug:"04-fold-expressions",title:"\u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions)",description:"C++17 \u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions) \u6559\u5b66\u793a\u4f8b",tags:["cpp17","fold_expressions"]},l="\u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions)",p={},i=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function u(r){const n={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,a.R)(),...r.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsx)(n.header,{children:(0,t.jsx)(n.h1,{id:"\u6298\u53e0\u8868\u8fbe\u5f0f-fold-expressions",children:"\u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions)"})}),"\n",(0,t.jsx)(n.p,{children:"C++17 \u6807\u51c6\u5f15\u5165\u7684 \u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,t.jsx)(n.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,t.jsx)(n.pre,{children:(0,t.jsx)(n.code,{className:"language-cpp",metastring:'title="cpp17/04_fold_expressions.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions)\r\n * \u6240\u5c5e\u6807\u51c6: C++17\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: \u5728\u53ef\u53d8\u53c2\u6570\u6a21\u677f (variadic templates) \u4e2d\uff0c\u7528\u7b80\u6d01\u7684\u8bed\u6cd5\r\n *          \u5bf9\u53c2\u6570\u5305\u8fdb\u884c\u6298\u53e0\uff08\u5f52\u7ea6\uff09\u8fd0\u7b97\u3002\r\n *          \u56db\u79cd\u5f62\u5f0f\uff1a\r\n *            \u4e00\u5143\u53f3\u6298\u53e0: (args op ...)\r\n *            \u4e00\u5143\u5de6\u6298\u53e0: (... op args)\r\n *            \u4e8c\u5143\u53f3\u6298\u53e0: (args op ... op init)\r\n *            \u4e8c\u5143\u5de6\u6298\u53e0: (init op ... op args)\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++11/14 \u4e2d\u5c55\u5f00\u53c2\u6570\u5305\u9700\u8981\u9012\u5f52\u6a21\u677f\u6216\u521d\u59cb\u5316\u5217\u8868\u6280\u5de7\uff0c\r\n *              \u4ee3\u7801\u5197\u957f\u4e14\u96be\u4ee5\u7406\u89e3\u3002\u6298\u53e0\u8868\u8fbe\u5f0f\u4e00\u884c\u641e\u5b9a\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - \u652f\u6301\u5927\u90e8\u5206\u4e8c\u5143\u8fd0\u7b97\u7b26\uff1a+  -  *  /  %  &  |  ^  <<  >>  &&  ||  ,\r\n *   - \u4e00\u5143\u6298\u53e0\u5bf9\u7a7a\u53c2\u6570\u5305\uff1a&& \u8fd4\u56de true\uff0c|| \u8fd4\u56de false\uff0c\u9017\u53f7\u8fd4\u56de void()\r\n *   - \u5176\u4ed6\u8fd0\u7b97\u7b26\u5bf9\u7a7a\u53c2\u6570\u5305\u662f\u7f16\u8bd1\u9519\u8bef \u2192 \u7528\u4e8c\u5143\u6298\u53e0\u63d0\u4f9b\u521d\u59cb\u503c\r\n *   - \u6298\u53e0\u8868\u8fbe\u5f0f\u5fc5\u987b\u7528\u5706\u62ec\u53f7\u5305\u88f9\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <string>\r\n#include <vector>\r\n#include <type_traits>\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. \u6c42\u548c\uff1a\u4e00\u5143\u5de6\u6298\u53e0 (... + args)\r\ntemplate<typename... Args>\r\nauto sum(Args... args) {\r\n    return (... + args);  // ((a1 + a2) + a3) + ...\r\n}\r\n\r\n// 2. \u5168\u90e8\u6253\u5370\uff1a\u4e00\u5143\u5de6\u6298\u53e0 + \u9017\u53f7\u8fd0\u7b97\u7b26\r\ntemplate<typename... Args>\r\nvoid print_all(Args&&... args) {\r\n    ((std::cout << args << " "), ...);\r\n    std::cout << "\\n";\r\n}\r\n\r\n// 3. \u903b\u8f91\u4e0e\uff1a\u4e00\u5143\u6298\u53e0\r\ntemplate<typename... Args>\r\nbool all_true(Args... args) {\r\n    return (... && args);  // \u7a7a\u53c2\u6570\u5305\u8fd4\u56de true\r\n}\r\n\r\n// 4. \u903b\u8f91\u6216\uff1a\u4e00\u5143\u6298\u53e0\r\ntemplate<typename... Args>\r\nbool any_true(Args... args) {\r\n    return (... || args);  // \u7a7a\u53c2\u6570\u5305\u8fd4\u56de false\r\n}\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- basic_usage ---\\n";\r\n\r\n    // \u6c42\u548c\r\n    std::cout << "sum(1,2,3,4,5) = " << sum(1, 2, 3, 4, 5) << "\\n";\r\n    std::cout << "sum(1.1, 2.2)  = " << sum(1.1, 2.2) << "\\n";\r\n\r\n    // \u6253\u5370\u6240\u6709\u53c2\u6570\r\n    std::cout << "print_all: ";\r\n    print_all(1, "hello", 3.14, \'A\');\r\n\r\n    // \u903b\u8f91\u8fd0\u7b97\r\n    std::cout << "all_true(true, true, true)  = " << all_true(true, true, true) << "\\n";\r\n    std::cout << "all_true(true, false, true) = " << all_true(true, false, true) << "\\n";\r\n    std::cout << "any_true(false, false, true) = " << any_true(false, false, true) << "\\n";\r\n\r\n    // \u7a7a\u53c2\u6570\u5305\r\n    std::cout << "all_true() [\u7a7a] = " << all_true() << " (\u9ed8\u8ba4 true)\\n";\r\n    std::cout << "any_true() [\u7a7a] = " << any_true() << " (\u9ed8\u8ba4 false)\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. \u4e8c\u5143\u6298\u53e0 \u2014\u2014 \u63d0\u4f9b\u521d\u59cb\u503c\uff0c\u5904\u7406\u7a7a\u53c2\u6570\u5305\r\ntemplate<typename... Args>\r\nauto safe_sum(Args... args) {\r\n    return (0 + ... + args);  // \u4e8c\u5143\u5de6\u6298\u53e0\uff0c\u521d\u59cb\u503c 0\r\n}\r\n\r\n// 2. \u5b57\u7b26\u4e32\u62fc\u63a5\r\ntemplate<typename... Args>\r\nstd::string concat(Args&&... args) {\r\n    return (std::string{} + ... + std::string(args));\r\n}\r\n\r\n// 3. \u7528\u6298\u53e0\u8868\u8fbe\u5f0f\u5b9e\u73b0 push_back \u5230 vector\r\ntemplate<typename T, typename... Args>\r\nvoid push_many(std::vector<T>& vec, Args&&... args) {\r\n    (vec.push_back(std::forward<Args>(args)), ...);\r\n}\r\n\r\n// 4. \u94fe\u5f0f\u6bd4\u8f83\uff1a\u68c0\u67e5\u6240\u6709\u503c\u662f\u5426\u76f8\u7b49\r\ntemplate<typename T, typename... Args>\r\nbool all_equal(T first, Args... rest) {\r\n    return ((first == rest) && ...);\r\n}\r\n\r\n// 5. \u6253\u5370\u5e26\u5206\u9694\u7b26\r\ntemplate<typename First, typename... Rest>\r\nvoid print_with_separator(const std::string& sep, First&& first, Rest&&... rest) {\r\n    std::cout << first;\r\n    ((std::cout << sep << rest), ...);\r\n    std::cout << "\\n";\r\n}\r\n\r\n// 6. \u8ba1\u7b97\u53c2\u6570\u4e2a\u6570\uff08\u5c55\u793a sizeof...\uff09\r\ntemplate<typename... Args>\r\nconstexpr std::size_t count_args(Args...) {\r\n    return sizeof...(Args);\r\n}\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- advanced_usage ---\\n";\r\n\r\n    // \u5b89\u5168\u6c42\u548c\uff08\u7a7a\u53c2\u6570\u5305\u8fd4\u56de 0\uff09\r\n    std::cout << "safe_sum()      = " << safe_sum() << "\\n";\r\n    std::cout << "safe_sum(1,2,3) = " << safe_sum(1, 2, 3) << "\\n";\r\n\r\n    // \u5b57\u7b26\u4e32\u62fc\u63a5\r\n    std::cout << "concat: " << concat("Hello", " ", "World", "!") << "\\n";\r\n\r\n    // push_many\r\n    std::vector<int> vec;\r\n    push_many(vec, 10, 20, 30, 40);\r\n    std::cout << "push_many: ";\r\n    for (auto v : vec) std::cout << v << " ";\r\n    std::cout << "\\n";\r\n\r\n    // all_equal\r\n    std::cout << "all_equal(5,5,5) = " << all_equal(5, 5, 5) << "\\n";\r\n    std::cout << "all_equal(5,5,3) = " << all_equal(5, 5, 3) << "\\n";\r\n\r\n    // \u5e26\u5206\u9694\u7b26\u6253\u5370\r\n    std::cout << "\u5206\u9694\u7b26\u6253\u5370: ";\r\n    print_with_separator(" | ", "Alice", "Bob", "Charlie");\r\n\r\n    // \u8ba1\u7b97\u53c2\u6570\u4e2a\u6570\r\n    std::cout << "\u53c2\u6570\u4e2a\u6570: " << count_args(1, "a", 3.14) << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u56db\u79cd\u6298\u53e0\u5f62\u5f0f\u5bf9\u6bd4\r\n// ============================================================\r\n\r\n// \u4e00\u5143\u53f3\u6298\u53e0: (args op ...)  => a1 op (a2 op (a3 op a4))\r\ntemplate<typename... Args>\r\nauto right_fold_sub(Args... args) {\r\n    return (args - ...);\r\n}\r\n\r\n// \u4e00\u5143\u5de6\u6298\u53e0: (... op args)  => ((a1 op a2) op a3) op a4\r\ntemplate<typename... Args>\r\nauto left_fold_sub(Args... args) {\r\n    return (... - args);\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9 / \u9677\u9631\r\n// ============================================================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- pitfalls ---\\n";\r\n\r\n    // \u9677\u9631 1: \u5de6\u6298\u53e0 vs \u53f3\u6298\u53e0\u7ed3\u679c\u4e0d\u540c\uff08\u975e\u4ea4\u6362\u8fd0\u7b97\u7b26\uff09\r\n    // \u5de6\u6298\u53e0: ((1-2)-3)-4 = -8\r\n    // \u53f3\u6298\u53e0: 1-(2-(3-4)) = -2\r\n    std::cout << "\u9677\u96311 - \u5de6\u6298\u53e0 (1-2-3-4): " << left_fold_sub(1, 2, 3, 4) << "\\n";\r\n    std::cout << "\u9677\u96311 - \u53f3\u6298\u53e0 (1-2-3-4): " << right_fold_sub(1, 2, 3, 4) << "\\n";\r\n\r\n    // \u9677\u9631 2: \u4e00\u5143\u6298\u53e0\u5bf9\u7a7a\u53c2\u6570\u5305 \u2014\u2014 \u53ea\u6709 &&\u3001||\u3001\u9017\u53f7 \u6709\u9ed8\u8ba4\u503c\r\n    //         sum() \u4f1a\u7f16\u8bd1\u9519\u8bef\uff01\u9700\u8981\u7528\u4e8c\u5143\u6298\u53e0\r\n    std::cout << "\u9677\u96312 - \u7a7a\u53c2\u6570\u5305\u7528\u4e8c\u5143\u6298\u53e0: safe_sum()=" << safe_sum() << "\\n";\r\n\r\n    // \u9677\u9631 3: \u6298\u53e0\u8868\u8fbe\u5f0f\u5fc5\u987b\u7528\u5706\u62ec\u53f7\u5305\u88f9\r\n    // return args + ...;    // \u9519\u8bef\uff01\r\n    // return (args + ...);  // \u6b63\u786e\r\n    std::cout << "\u9677\u96313 - \u6298\u53e0\u8868\u8fbe\u5f0f\u5fc5\u987b\u7528\u5706\u62ec\u53f7 () \u5305\u88f9\\n";\r\n\r\n    // \u9677\u9631 4: \u8fd0\u7b97\u7b26\u4f18\u5148\u7ea7 \u2014\u2014 \u6298\u53e0\u8868\u8fbe\u5f0f\u5185\u4e0d\u8981\u6df7\u5408\u8fd0\u7b97\u7b26\r\n    // (args + ... * init) \u662f\u975e\u6cd5\u7684 \u2014\u2014 \u6298\u53e0\u53ea\u80fd\u6709\u4e00\u4e2a\u8fd0\u7b97\u7b26\r\n    std::cout << "\u9677\u96314 - \u6298\u53e0\u8868\u8fbe\u5f0f\u5185\u53ea\u80fd\u6709\u4e00\u4e2a\u8fd0\u7b97\u7b26\\n";\r\n\r\n    // \u9677\u9631 5: \u9017\u53f7\u6298\u53e0\u7684\u526f\u4f5c\u7528\u987a\u5e8f\u662f\u786e\u5b9a\u7684\uff08\u4ece\u5de6\u5230\u53f3\uff09\r\n    std::cout << "\u9677\u96315 - \u9017\u53f7\u6298\u53e0\u987a\u5e8f: ";\r\n    auto print_indexed = [](auto... args) {\r\n        int i = 0;\r\n        ((std::cout << "[" << i++ << "]=" << args << " "), ...);\r\n        std::cout << "\\n";\r\n    };\r\n    print_indexed("a", "b", "c");\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== \u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions) - C++17 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,t.jsx)(n.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,t.jsxs)(n.ul,{children:["\n",(0,t.jsx)(n.li,{children:(0,t.jsx)(n.a,{href:"https://en.cppreference.com/w/cpp/language/fold",children:"cppreference: \u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions)"})}),"\n"]})]})}function c(r={}){const{wrapper:n}={...(0,a.R)(),...r.components};return n?(0,t.jsx)(n,{...r,children:(0,t.jsx)(u,{...r})}):u(r)}},28453(r,n,e){e.d(n,{R:()=>o,x:()=>l});var s=e(96540);const t={},a=s.createContext(t);function o(r){const n=s.useContext(a);return s.useMemo(function(){return"function"==typeof r?r(n):{...n,...r}},[n,r])}function l(r){let n;return n=r.disableParentContext?"function"==typeof r.components?r.components(t):r.components||t:o(r.components),s.createElement(a.Provider,{value:n},r.children)}}}]);